mapper.select:
select spsg.id as rowId,csu.account as account,csu.name as name,csu.id as expert
from srm_project_solicit_grade spsg
left join ct_srm_user csu on csu.id=spsg.expert
where is_cancel=0

    and spsg.sys_no=#{projectSolicitGradeDto.sysNo}


    and spsg.project_id=#{projectSolicitGradeDto.projectId}


    and spsg.prj_type=#{projectSolicitGradeDto.prjType}


    and spsg.allot_count=#{projectSolicitGradeDto.allotCount}

select spsg.id as rowId,csy.name as yearName, spst.proj_type, spst.title as projectName,spsg.project_id as projectId,
       csu.name as applyUserName, spst.sub_date as subDate,spsg.note as note,
       spsg.audit_status as auditStatus,spsg.data_status as dataStatus
from srm_project_solicit_grade spsg,srm_project_solicit spst
left join ct_srm_user csu on csu.id=spst.sub_user_id
left join ct_srm_year csy on csy.code=spst.year
where is_cancel=0 and spsg.expert=#{projectSolicitDto.userId} and spsg.sys_no=#{projectSolicitDto.sysNo} and spst.id=spsg.project_id

    and spst.title LIKE CONCAT('%', #{projectSolicitDto.title}, '%')


    and spst.year=#{projectSolicitDto.year}


    and spst.sub_date >= #{projectSolicitDto.startDate}



    and spst.sub_date <= #{projectSolicitDto.endDate}


    and spsg.audit_status=#{projectSolicitDto.auditStatus}


    and spsg.data_status=#{projectSolicitDto.dataStatus}
